import { useState } from "react";

import {
  Container,
  Typography,
  Box,
  AppBar,
  Toolbar,
  Button,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Paper,
  Pagination,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = Array.from({ length: 25 }, (_, i) => ({
    id: i + 1,
    title: `게시글 ${i + 1}`,
    content: `내용 ${i + 1}`,
  }));

  const [page, setPage] = useState(1);
  const pageSize = 9;

  const handleChange = (event, value) => {
    setPage(value);
  };

  const startIndex = (page - 1) * pageSize;

  const currentPosts = posts.slice(
    startIndex,
    startIndex + pageSize
  );

  return (
    <>
      {/* Navbar */}
      <AppBar position="static" className="navbar">
        <Toolbar className="navbar-toolbar">

          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

          <Box sx={{ marginLeft: "auto" }}>
            <Button className="nav-button">
              게시물 등록
            </Button>

            <Button className="nav-button logout-btn">
              로그아웃
            </Button>
          </Box>

        </Toolbar>
      </AppBar>

      {/* 배너 */}
      <Box className="board-header">
        <Typography variant="h4" className="board-title">
          게시판
        </Typography>

        <Typography className="board-subtitle">
          공지사항 및 게시글 목록
        </Typography>
      </Box>

      {/* 테이블 */}
      <Container className="board-container">

        <Paper className="board-table-wrapper">

          <Table>

            <TableHead>
              <TableRow className="table-head">
                <TableCell>ID</TableCell>
                <TableCell>제목</TableCell>
                <TableCell>작성일</TableCell>
              </TableRow>
            </TableHead>

            <TableBody>
              {currentPosts.map((post) => (
                <TableRow
                  key={post.id}
                  className="table-row"
                >
                  <TableCell>{post.id}</TableCell>
                  <TableCell>{post.title}</TableCell>
                  <TableCell>{post.content}</TableCell>
                </TableRow>
              ))}
            </TableBody>

          </Table>

        </Paper>

        {/* 페이지네이션 */}
        <Box
          sx={{
            display: "flex",
            justifyContent: "center",
            mt: 3,
          }}
        >
          <Pagination
            count={Math.ceil(posts.length / pageSize)}
            page={page}
            onChange={handleChange}
            color="primary"
          />
        </Box>

      </Container>
    </>
  );
}

export default BoardPage;
